**Solution** : Créer une fonction `validateField(name, value)` appelée dans `handleChange` après la mise à jour de l'état.

```jsx
const validateField = (name, value) => {
  const newError = {};

  switch(name) {
    case 'password':
      if (value.length > 0 && value.length < 6) {
        newError[name] = 'Le mot de passe doit contenir au moins 6 caractères';
      }
      // Vérifier aussi la confirmation si elle existe
      if (formData.confirmPassword && value !== formData.confirmPassword) {
        newError.confirmPassword = 'Les mots de passe ne correspondent pas';
      }
      break;
    case 'confirmPassword':
      if (value !== formData.password) {
        newError[name] = 'Les mots de passe ne correspondent pas';
      }
      break;
    case 'email':
      const emailRegex = /^[^\s@]+@([^\s@]+\.)+[^\s@]+$/;
      if (value && !emailRegex.test(value)) {
        newError[name] = 'Email invalide';
      }
      break;
    // autres champs...
  }

  setErrors(prev => ({ ...prev, ...newError, [name]: newError[name] || '' }));
};

const handleChange = (e) => {
  const { name, value, type, checked } = e.target;
  const newValue = type === 'checkbox' ? checked : value;

  setFormData(prev => ({ ...prev, [name]: newValue }));
  validateField(name, newValue);  // Validation en temps réel
};
```

**Avantage** : L'utilisateur voit immédiatement si son mot de passe est trop court, sans attendre la soumission. Cela améliore l'expérience utilisateur.

```jsx
import { useState } from 'react';

function TodoList() {
  const [todos, setTodos] = useState([
    { id: 1, text: 'Apprendre React', completed: false },
    { id: 2, text: 'Maîtriser les événements', completed: false },
    { id: 3, text: 'Créer un projet', completed: true }
  ]);

  const [editingId, setEditingId] = useState(null);
  const [editText, setEditText] = useState('');

  // MÉTHODE 1 : Fonction fléchée dans le onClick (avec paramètre)
  const deleteTodo = (id) => {
    setTodos(todos.filter(todo => todo.id !== id));
  };

  // MÉTHODE 2 : bind() - alternative
  const toggleComplete = (id) => {
    setTodos(todos.map(todo =>
      todo.id === id ? { ...todo, completed: !todo.completed } : todo
    ));
  };

  const startEditing = (todo) => {
    setEditingId(todo.id);
    setEditText(todo.text);
  };

  const saveEdit = (id) => {
    setTodos(todos.map(todo =>
      todo.id === id ? { ...todo, text: editText } : todo
    ));
    setEditingId(null);
    setEditText('');
  };

  return (
    &lt;div className="todo-list"&gt;
      &lt;h2&gt;Ma liste de tâches&lt;/h2&gt;
      &lt;ul&gt;
        {todos.map(todo => (
          &lt;li key={todo.id} className={`todo-item ${todo.completed ? 'line-through' : ''}`}&gt;
            {editingId === todo.id ? (
              &lt;&gt;
                &lt;input
                  type="text"
                  value={editText}
                  onChange={(e) => setEditText(e.target.value)}
                  onKeyPress={(e) => e.key === 'Enter' && saveEdit(todo.id)}
                /&gt;
                &lt;button onClick={() => saveEdit(todo.id)}&gt;💾&lt;/button&gt;
                &lt;button onClick={() => setEditingId(null)}&gt;❌&lt;/button&gt;
              &lt;/&gt;
            ) : (
              &lt;&gt;
                &lt;span onClick={() => toggleComplete(todo.id)} style={{ cursor: 'pointer' }}&gt;
                  {todo.text}
                &lt;/span&gt;
                &lt;button onClick={() => startEditing(todo)}&gt;✏️ Modifier&lt;/button&gt;
                &lt;button onClick={() => deleteTodo(todo.id)}&gt;🗑️ Supprimer&lt;/button&gt;
              &lt;/&gt;
            )}
          &lt;/li&gt;
        ))}
      &lt;/ul&gt;
    &lt;/div&gt;
  );
}
```

**Trois façons de passer des arguments :**

**1. Fonction fléchée dans le `onClick` (la plus courante)**
```jsx
&lt;button onClick={() => deleteTodo(todo.id)}&gt;Supprimer&lt;/button&gt;
```
*Avantage* : Simple et lisible. Crée une nouvelle fonction à chaque rendu, mais l'impact est négligeable pour la plupart des cas.

**2. Utilisation de `bind()`**
```jsx
&lt;button onClick={deleteTodo.bind(null, todo.id)}&gt;Supprimer&lt;/button&gt;
```
*Avantage* : Crée la fonction une fois (pas de nouvelle fonction à chaque rendu). *Inconvénient* : Syntaxe moins intuitive.

**3. Fonction gestionnaire qui retourne une fonction**
```jsx
const deleteHandler = (id) => {
  return () => {
    deleteTodo(id);
  };
};

// Dans le JSX
&lt;button onClick={deleteHandler(todo.id)}&gt;Supprimer&lt;/button&gt;
```
*Avantage* : Permet d'encapsuler de la logique supplémentaire. *Inconvénient* : Plus verbeux.

**Recommandation** : Pour la plupart des cas, utilisez la fonction fléchée. Pour les composants très performants avec `React.memo`, privilégiez `useCallback` combiné avec une des méthodes.

**Optimisation avec `useCallback` :**

```jsx
import { useState, useCallback } from 'react';

function TodoList() {
  const [todos, setTodos] = useState([...]);

  // useCallback mémorise la fonction entre les rendus
  const deleteTodo = useCallback((id) => {
    setTodos(prevTodos => prevTodos.filter(todo => todo.id !== id));
  }, []);  // Tableau de dépendances vide : fonction stable

  const toggleComplete = useCallback((id) => {
    setTodos(prevTodos => 
      prevTodos.map(todo =>
        todo.id === id ? { ...todo, completed: !todo.completed } : todo
      )
    );
  }, []);

  return (
    &lt;ul&gt;
      {todos.map(todo => (
        &lt;TodoItem
          key={todo.id}
          todo={todo}
          onDelete={deleteTodo}
          onToggle={toggleComplete}
        /&gt;
      ))}
    &lt;/ul&gt;
  );
}

// Composant enfant optimisé avec React.memo
const TodoItem = React.memo(({ todo, onDelete, onToggle }) => {
  console.log(`Rendu de ${todo.id}`);
  return (
    &lt;li&gt;
      &lt;span onClick={() => onToggle(todo.id)}&gt;{todo.text}&lt;/span&gt;
      &lt;button onClick={() => onDelete(todo.id)}&gt;Supprimer&lt;/button&gt;
    &lt;/li&gt;
  );
});
```

**Pourquoi c'est utile pour les listes :**
1. **Évite les re-rendus inutiles** : Sans `useCallback`, une nouvelle fonction `deleteTodo` est créée à chaque rendu du parent. Même avec `React.memo`, le composant enfant se re-rend car la prop `onDelete` a changé (nouvelle référence).
2. **Performance sur les grandes listes** : Pour 1000 tâches, éviter des re-rendus inutiles améliore significativement les performances.
3. **Utilisation de la forme fonctionnelle** : `setTodos(prev => ...)` pour éviter la dépendance à `todos` dans le tableau de dépendances.

**Forme fonctionnelle** : En utilisant `prevTodos` dans `setTodos`, on n'a pas besoin d'inclure `todos` dans les dépendances du `useCallback`, ce qui rend la fonction stable.
